sharedCss:
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    body {
      background-color: #faf9f7;
      font-family: Georgia, 'Times New Roman', serif;
      font-size: 16px;
      line-height: 1.8;
      color: #2c2c2c;
    }

    .page {
      width: 100%;
      background-color: #fff;
      padding: 48px 25px;
    }

    @media (max-width: 600px) {
      .page {
        padding: 24px 25px;
      }
    }

    /* Header */
    .header {
      text-align: center;
      margin-bottom: 2em;
    }

    .header .institution {
      font-variant: small-caps;
      font-weight: bold;
      text-transform: uppercase;
      color: #5a4a1e;
      font-size: 1em;
      letter-spacing: 0.05em;
    }

    .header .occasion {
      font-weight: bold;
      font-size: 1.35em;
      color: #3a2e10;
      margin-top: 0.2em;
    }

    .header .addressee {
      font-style: italic;
      color: #555;
      margin-top: 0.3em;
    }

    /* Salutation */
    .salutation {
      font-style: italic;
      font-weight: bold;
      color: #5a4a1e;
      margin-bottom: 1.3em;
    }

    /* Body paragraphs */
    p {
      text-align: justify;
      margin-bottom: 1.3em;
    }

    /* Closing / signature */
    .signature {
      font-style: italic;
      color: #5a4a1e;
      margin-top: 1.8em;
    }

    /* Footer */
    .footer {
      text-align: center;
      font-size: 0.8em;
      color: #888;
      margin-top: 2.5em;
    }

    .footer a {
      color: #888;
    }
